import{_ as t,o,c as r,a2 as n}from"./chunks/framework.Bk_3gXAz.js";const g=JSON.parse('{"title":"CodyMaster Brain: The Cognitive Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"brain.md","filePath":"brain.md"}'),a={name:"brain.md"};function i(s,e,d,c,l,m){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="codymaster-brain-the-cognitive-architecture" tabindex="-1">CodyMaster Brain: The Cognitive Architecture <a class="header-anchor" href="#codymaster-brain-the-cognitive-architecture" aria-label="Permalink to &quot;CodyMaster Brain: The Cognitive Architecture&quot;">​</a></h1><p>Standard AI systems treat memory as an append-only log, inevitably leading to overloaded context, &quot;goldfish memory&quot;, and recurring hallucinations. <strong>CodyMaster Brain</strong> addresses this by implementing a biomimetic memory architecture inspired by human cognitive processes. It doesn&#39;t just store information; it synthesizes, filters, and selectively forgets.</p><h2 id="the-five-tier-memory-system" tabindex="-1">The Five-Tier Memory System <a class="header-anchor" href="#the-five-tier-memory-system" aria-label="Permalink to &quot;The Five-Tier Memory System&quot;">​</a></h2><p>CodyMaster implements a unified memory pipeline with five distinct tiers, each serving a specific cognitive function — from millisecond reflexes to permanent structural understanding.</p><h3 id="tier-1-sensory-memory" tabindex="-1">Tier 1: Sensory Memory <a class="header-anchor" href="#tier-1-sensory-memory" aria-label="Permalink to &quot;Tier 1: Sensory Memory&quot;">​</a></h3><p><em>Transient, single-command context — forgotten immediately.</em></p><p>Temporary information within one command execution: &quot;file X has 200 lines.&quot; Discarded instantly after use because it has no long-term value. Like hearing a phone number once — gone in seconds.</p><h3 id="tier-2-working-memory-cm-continuity" tabindex="-1">Tier 2: Working Memory (<code>cm-continuity</code>) <a class="header-anchor" href="#tier-2-working-memory-cm-continuity" aria-label="Permalink to &quot;Tier 2: Working Memory (`cm-continuity`)&quot;">​</a></h3><p><em>Active session state — persists 7 days.</em></p><p>Just as humans can only hold about 7 items in short-term memory, CodyMaster maintains strict working memory limits. Managed by the <strong><a href="/docs/skills/cm-continuity"><code>cm-continuity</code></a></strong> skill, this layer tracks the active task, recent context, mistakes made, and immediate goals via <code>CONTINUITY.md</code>.</p><ul><li><strong>When to use:</strong> Automatically loaded at session start, saved at session end.</li></ul><h3 id="tier-3-long-term-memory-context-backbone-v5" tabindex="-1">Tier 3: Long-Term Memory (Context Backbone v5) <a class="header-anchor" href="#tier-3-long-term-memory-context-backbone-v5" aria-label="Permalink to &quot;Tier 3: Long-Term Memory (Context Backbone v5)&quot;">​</a></h3><p><em>Experience-based learnings — <code>StorageBackend</code> abstraction (SQLite/OpenViking).</em></p><p>When bugs are fixed or patterns discovered, key insights are pushed to the <strong>Context Backbone v5</strong>. Depending on your <code>.cm/config.yaml</code>, this abstracts over two engines:</p><ol><li><strong>SqliteBackend</strong>: Local WAL-mode SQLite database using FTS5 for lightning-fast localized text searches.</li><li><strong>VikingBackend</strong>: A robust REST-based semantic vector memory powered by the <strong>OpenViking</strong> daemon (<code>http://localhost:1933</code>).</li></ol><p>Both engines support <strong>Token Budget Enforcement</strong>—pre-allocating a precise max tokens budget limit for learnings per prompt. Only learnings relevant to the current module are loaded per task via progressive indexing (L0/L1/L2) and semantic filtering.</p><h3 id="tier-4-semantic-memory-openviking" tabindex="-1">Tier 4: Semantic Memory (OpenViking) <a class="header-anchor" href="#tier-4-semantic-memory-openviking" aria-label="Permalink to &quot;Tier 4: Semantic Memory (OpenViking)&quot;">​</a></h3><p><em>Deep document retrieval — permanent, true vector search.</em></p><p>When context exceeds working memory capacity, CodyMaster interacts with the <strong>OpenViking</strong> daemon <code>/search</code> and <code>/abstract</code> endpoints (or <code>qmd</code> as a local fallback). This yields true <strong>vector similarity</strong> across massive codebases and documentation—even when query terms don&#39;t match exactly (e.g. &quot;async timeout&quot; matches &quot;network latency spike&quot;). Like a photographic reading memory — it finds patterns hidden in deep codebase semantics.</p><h3 id="tier-5-structural-memory-cm-codeintell" tabindex="-1">Tier 5: Structural Memory (<code>cm-codeintell</code>) <a class="header-anchor" href="#tier-5-structural-memory-cm-codeintell" aria-label="Permalink to &quot;Tier 5: Structural Memory (`cm-codeintell`)&quot;">​</a></h3><p><em>Real-time code architecture understanding — AST/CodeGraph.</em></p><p><strong><a href="/docs/skills/cm-codeintell"><code>cm-codeintell</code></a></strong> provides a 4-layer intelligence system that pre-indexes code structure for instant understanding:</p><table tabindex="0"><thead><tr><th>Layer</th><th>Name</th><th>Speed</th><th>Best For</th></tr></thead><tbody><tr><td><strong>0</strong></td><td>Skeleton Index</td><td>&lt;4s</td><td>Any project — zero dependencies</td></tr><tr><td><strong>1</strong></td><td>Code Graph</td><td>~30s</td><td>50+ files — call chains, impact analysis</td></tr><tr><td><strong>2</strong></td><td>Architecture</td><td>~10s</td><td>20+ files — visual module map</td></tr><tr><td><strong>3</strong></td><td>Smart Context</td><td>~5s</td><td>Task-focused context packets</td></tr></tbody></table><p>Achieves <strong>95% token compression</strong> by reading AST structure, not raw code. Like an innate sense of spatial awareness for your codebase.</p><hr><h2 id="the-cloud-brain-cm-notebooklm" tabindex="-1">The Cloud Brain (<code>cm-notebooklm</code>) <a class="header-anchor" href="#the-cloud-brain-cm-notebooklm" aria-label="Permalink to &quot;The Cloud Brain (`cm-notebooklm`)&quot;">​</a></h2><p>Beyond the 5-tier local pipeline, CodyMaster implements a <strong>Cloud Brain</strong> powered by Google&#39;s NotebookLM for cross-machine persistence:</p><ul><li><strong>Master Brain (<code>codymaster</code>)</strong>: A global knowledge base storing cross-project meta-learnings and architecture patterns.</li><li><strong>Project Brains (<code>project_id</code>)</strong>: Isolated NotebookLM instances for each project containing domain-specific PRDs, APIs, and business logic.</li><li><strong>Wisdom Gatekeeper</strong>: Uses the Rule of 3 (recurring ≥ 3 times) to filter noise. Only qualified &quot;Graduated Wisdom&quot; is pushed to the global Master Brain.</li><li><strong>Audio Onboarding</strong>: Converts complex project knowledge into Spotify-style podcasts for new developers.</li><li><strong>Flashcard Learning</strong>: Auto-generated flashcards from the codebase help engineers quickly learn the stack.</li></ul><p>The <strong><a href="/docs/skills/cm-notebooklm"><code>cm-notebooklm</code></a></strong> skill orchestrates this cloud sync via <code>brain-sync.sh</code>.</p><hr><h2 id="biomimetic-mechanisms" tabindex="-1">Biomimetic Mechanisms <a class="header-anchor" href="#biomimetic-mechanisms" aria-label="Permalink to &quot;Biomimetic Mechanisms&quot;">​</a></h2><p>CodyMaster Brain implements dynamic mechanisms to manage the lifecycle of information.</p><h3 id="smart-decay-the-forgetting-curve" tabindex="-1">Smart Decay (The Forgetting Curve) <a class="header-anchor" href="#smart-decay-the-forgetting-curve" aria-label="Permalink to &quot;Smart Decay (The Forgetting Curve)&quot;">​</a></h3><p>Standard AI systems hold onto outdated knowledge forever, leading to bugs when dependencies change. CodyMaster Brain implements a decay mechanism inspired by the <em>Ebbinghaus Forgetting Curve</em>. Old refactored code patterns and obsolete learnings literally &quot;decay&quot; and expire, keeping your active context clean and highly relevant.</p><h3 id="self-healing-feedback-loops" tabindex="-1">Self-Healing Feedback Loops <a class="header-anchor" href="#self-healing-feedback-loops" aria-label="Permalink to &quot;Self-Healing Feedback Loops&quot;">​</a></h3><p>When a bug leads to an infinite loop or a hallucination, CodyMaster Brain recognizes the pattern and &quot;heals&quot; its memory. The new <strong>Self-Healing AI Pipeline</strong> (<code>cm-skill-health</code>, <code>cm-skill-evolution</code>) continuously monitors success rates and auto-patches failing skills using a version DAG.</p><h3 id="progressive-loading-budget-constraints" tabindex="-1">Progressive Loading &amp; Budget Constraints <a class="header-anchor" href="#progressive-loading-budget-constraints" aria-label="Permalink to &quot;Progressive Loading &amp; Budget Constraints&quot;">​</a></h3><p>Instead of loading a massive data file on every request, the Context Backbone heavily relies on <strong>cm:// URIs</strong> and <strong>L0/L1/L2 progressive loading</strong>. For example, an initial hit fetches an L0 index (saving up to 96% of tokens), and only escalates to a full file read if deeper understanding is necessary. Combined with <strong>Token Budget Enforcement</strong>, this prevents context window overflow.</p><hr><h2 id="integrating-core-memory-skills" tabindex="-1">Integrating Core Memory Skills <a class="header-anchor" href="#integrating-core-memory-skills" aria-label="Permalink to &quot;Integrating Core Memory Skills&quot;">​</a></h2><p>To fully utilize the CodyMaster Brain, these core skills should be wired into your standard workflow:</p><table tabindex="0"><thead><tr><th>Skill</th><th>Role in Memory Architecture</th><th>Usage</th></tr></thead><tbody><tr><td>🧠 <strong><a href="/docs/skills/cm-continuity"><code>cm-continuity</code></a></strong></td><td><strong>Working Memory Engine</strong></td><td>Run at the start and end of complex sessions to maintain state across boundaries without bloating the prompt.</td></tr><tr><td>🔍 <strong><a href="/docs/skills/cm-deep-search"><code>cm-deep-search</code></a></strong></td><td><strong>Semantic Retrieval</strong></td><td>When the context exceeds the working memory capacity, this skill intelligently fetches relevant knowledge using BM25 or vector search.</td></tr><tr><td>🏗️ <strong><a href="/docs/skills/cm-codeintell"><code>cm-codeintell</code></a></strong></td><td><strong>Structural Intelligence</strong></td><td>Pre-indexes codebase architecture (AST, CodeGraph) so AI understands code structure with 95% token compression.</td></tr><tr><td>☁️ <strong><a href="/docs/skills/cm-notebooklm"><code>cm-notebooklm</code></a></strong></td><td><strong>Cloud Brain Sync</strong></td><td>Synchronizes high-value project knowledge to Google NotebookLM for cross-machine persistence and audio/flashcard generation.</td></tr><tr><td>🗄️ <strong><a href="/docs/skills/cm-dockit"><code>cm-dockit</code></a></strong></td><td><strong>Knowledge Organizer</strong></td><td>Analyzes codebases and generates structured, LLM-readable knowledge bases (<code>AGENTS.md</code>, SOPs) that the brain can rapidly query.</td></tr><tr><td>👑 <strong><a href="/docs/skills/cm-skill-mastery"><code>cm-skill-mastery</code></a></strong></td><td><strong>Meta-Cognition</strong></td><td>Helps the AI &quot;think about thinking,&quot; knowing which memory structures to access and how to sequence them effectively.</td></tr></tbody></table><p>By mirroring human memory systems — with 5 cognitive tiers, cloud synchronization, smart decay, and self-healing loops — CodyMaster Brain turns the AI from a stateless code generator into a contextual engineering partner that learns, remembers, and grows across sessions and machines.</p>',43)])])}const u=t(a,[["render",i]]);export{g as __pageData,u as default};
